// Trigger payload: number 0..100 (percent), or string "disable",
// or numeric string "0..100". Initialize symo state and emit the
// first modbus read (SunS marker @ 40000, qty 2).
const SUNSPEC_BASE = 40000;
const UNIT = 1;
let mode, percent;
const p = msg.payload;
if (p === 'disable' || p === 'DISABLE') {
    mode = 'disable';
} else {
    const n = (typeof p === 'number') ? p : parseFloat(p);
    if (!isFinite(n) || n < 0 || n > 100) {
        node.error('symo: invalid trigger payload ' + JSON.stringify(p), msg);
        return null;
    }
    mode = 'percent';
    percent = n;
}
msg.symo = {
    mode: mode, percent: percent,
    step: 'check_marker', walkAddr: SUNSPEC_BASE, base: null,
    raw: null, sf: null
};
msg.payload = { fc: 3, unitid: UNIT, address: SUNSPEC_BASE, quantity: 2 };
return msg;

// State machine driving the SunSpec walk + writes.
// Inputs: from flex-getter (msg.payload = uint16 array, msg.symo preserved
// by keepMsgProperties=true) or from flex-write (msg.payload = response,
// msg.symo preserved). Outputs:
//   0 -> flex-getter (next read)
//   1 -> flex-write  (next write)
//   2 -> status/log
const UNIT = 1;
const SUNS_MARKER = [0x5375, 0x6E53];
const TARGET_MODEL = 123;
const END_MARKER = 0xFFFF;
const OFF_PCT      = 5;
const OFF_RVRT     = 7;
const OFF_ENA      = 9;
const OFF_PCT_SF   = 23;

const sym = msg.symo;
if (!sym) {
    node.warn('symo controller: no msg.symo (keepMsgProperties off?)');
    return [null, null, { payload: { error: 'lost state' } }];
}

function read(addr, qty) {
    return { payload: { fc: 3, unitid: UNIT, address: addr, quantity: qty }, symo: sym };
}
function write(addr, value) {
    return { payload: { fc: 6, unitid: UNIT, address: addr, value: value, quantity: 1 }, symo: sym };
}
function done(detail) {
    return { payload: detail, topic: 'red/cmd/symo/setlimit/result' };
}

// Normalize getter payload to a plain number array
let regs = msg.payload;
if (regs && typeof regs === 'object' && Array.isArray(regs.data)) regs = regs.data;
if (Buffer.isBuffer(regs)) {
    const arr = [];
    for (let i = 0; i + 1 < regs.length; i += 2) arr.push(regs.readUInt16BE(i));
    regs = arr;
}

if (sym.step === 'check_marker') {
    if (!Array.isArray(regs) || regs[0] !== SUNS_MARKER[0] || regs[1] !== SUNS_MARKER[1]) {
        return [null, null, done({ ok: false, error: 'SunS marker not found', got: regs })];
    }
    sym.step = 'walk';
    sym.walkAddr = 40002;
    return [read(sym.walkAddr, 2), null, null];
}

if (sym.step === 'walk') {
    if (!Array.isArray(regs) || regs.length < 2) {
        return [null, null, done({ ok: false, error: 'walk read returned no data', got: regs })];
    }
    const model_id = regs[0];
    const length = regs[1];
    if (model_id === END_MARKER) {
        return [null, null, done({ ok: false, error: 'Model ' + TARGET_MODEL + ' not present' })];
    }
    if (model_id === TARGET_MODEL) {
        sym.base = sym.walkAddr;
        if (sym.mode === 'disable') {
            sym.step = 'write_disable';
            return [null, write(sym.base + OFF_ENA, 0), null];
        }
        sym.step = 'read_sf';
        return [read(sym.base + OFF_PCT_SF, 1), null, null];
    }
    sym.walkAddr += 2 + length;
    return [read(sym.walkAddr, 2), null, null];
}

if (sym.step === 'read_sf') {
    const sfRaw = regs[0];
    const sf = sfRaw >= 0x8000 ? sfRaw - 0x10000 : sfRaw;
    const raw = Math.round(sym.percent * Math.pow(10, -sf));
    if (raw < 0 || raw > 0xFFFF) {
        return [null, null, done({ ok: false, error: 'raw out of uint16 range', raw, percent: sym.percent, sf })];
    }
    sym.raw = raw;
    sym.sf = sf;
    sym.step = 'write_pct';
    return [null, write(sym.base + OFF_PCT, raw), null];
}

if (sym.step === 'write_pct') {
    sym.step = 'write_rvrt';
    return [null, write(sym.base + OFF_RVRT, 0), null];
}

if (sym.step === 'write_rvrt') {
    sym.step = 'write_ena';
    return [null, write(sym.base + OFF_ENA, 1), null];
}

if (sym.step === 'write_ena') {
    return [null, null, done({ ok: true, percent: sym.percent, raw: sym.raw, sf: sym.sf, base: sym.base })];
}

if (sym.step === 'write_disable') {
    return [null, null, done({ ok: true, disabled: true, base: sym.base })];
}

node.warn('symo controller: unknown step ' + sym.step);
return [null, null, done({ ok: false, error: 'unknown step', step: sym.step })];
